#include <bits/stdc++.h>
using namespace std;
const int N=105,M=10005;
int n,f[N],cnt,ans;
struct node
{
	int x,y,z;
	bool operator<(const node other) const
	{
		return z<other.z;
	}
} a[M];
int find(int x)
{
	if(f[x]==x) return x;
	return f[x]=find(f[x]);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		f[i]=i;
		for(int j=1;j<=n;j++)
		{
			if(i>=j)
			{
				int t;
				cin>>t;
				continue;
			}
			cin>>a[++cnt].z;
			a[cnt].x=i,a[cnt].y=j;
		}
	}
	sort(a+1,a+1+cnt);
	for(int i=1;i<=cnt;i++)
	{
		int fa=find(a[i].x),fb=find(a[i].y);
		if(fa!=fb)
		{
			ans+=a[i].z;
			f[fa]=fb;
		}
	}
	cout<<ans;
	return 0;

}
